// Re-assert each ensures-forall so Verus picks up triggers in both runs.
assert(forall|v: T| #![auto] post1_self_@.contains(v) ==>
    pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
assert(forall|v: T| #![auto] post2_self_@.contains(v) ==>
    pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

// Tuple-component equalities: both runs are pinned to the same pre-state expressions.
assert(r1.0 == pre_self_@[0]);
assert(r2.0 == pre_self_@[0]);
assert(r1.0 == r2.0);
assert(r1.1 == pre_self_.get_node_ref(r1.0));
assert(r2.1 == pre_self_.get_node_ref(r2.0));
assert(r1.1 == r2.1);

// Both post-state views collapse to pre_self_@.skip(1), so they agree.
assert(post1_self_@ == pre_self_@.skip(1));
assert(post2_self_@ == pre_self_@.skip(1));
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);

// Bridge the two get_node_ref foralls through pre_self_.get_node_ref(v).
assert forall|v: T| post1_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post2_self_@.contains(v));
}
